+    let pos_b = order.iter().position(|x| x == "b").unwrap();
+    let pos_c = order.iter().position(|x| x == "c").unwrap();
+    let pos_d = order.iter().position(|x| x == "d").unwrap();
+    assert!(pos_a < pos_b);
+    assert!(pos_a < pos_c);
+    assert!(pos_b < pos_d);
